from collections import defaultdict, Counter

class InvertedIndex:
    def __init__(self):
        self.index = {}         # term -> sorted list of doc_ids
        self.tf = {}            # (term, doc_id) -> count

    def build(self, corpus: list) -> None:
        postings = defaultdict(set)
        for doc_id, doc in enumerate(corpus):
            tf_counts = Counter(doc)
            for term, count in tf_counts.items():
                postings[term].add(doc_id)
                self.tf[(term, doc_id)] = count
        # Sort postings lists
        self.index = {term: sorted(doc_ids) for term, doc_ids in postings.items()}

    def get_postings(self, term: str) -> list:
        return self.index.get(term, [])

    def and_query(self, terms: list) -> list:
        if not terms:
            return []
        result = set(self.get_postings(terms[0]))
        for term in terms[1:]:
            result &= set(self.get_postings(term))
        return sorted(result)

    def or_query(self, terms: list) -> list:
        if not terms:
            return []
        result = set()
        for term in terms:
            result |= set(self.get_postings(term))
        return sorted(result)

    def term_frequency(self, term: str, doc_id: int) -> int:
        return self.tf.get((term, doc_id), 0)
